import React, { useEffect } from "react";
import ChartsDashboard from "./chart";
import { useDispatch } from "react-redux";
import { clearFilterDashboard } from "../../stores/slices/dashboard.slice";
import PageAccessGate from "../../components/pageAccess/PageAccessGate";

const Dashboard = () => {
  const dispatch = useDispatch();
  useEffect(() => {
    return () => {
      dispatch(clearFilterDashboard());
    };
  }, []);
  return (
    <PageAccessGate permissionsNeeded={["dashboard.view"]}>
      <ChartsDashboard />
    </PageAccessGate>
  );
};

export default Dashboard;

import { createSlice, createAsyncThunk } from "@reduxjs/toolkit";
import _ from "lodash";
import { handleError } from "../../utils/handleError";
import { 
  getLineChartApi, 
  getRevenueChartApi, 
  getExpenseChartApi 
} from "../../apis/dashboard.api";

export const fetchDataLineChart = createAsyncThunk(
  "dashboards/fetchDataLineChart",
  async (values, { rejectWithValue }) => {
    try {
      const res = await getLineChartApi(values);
      if (!res) return rejectWithValue("Failed to fetch dashboards");

      return res.data;
    } catch (err) {
      const errorMsg = handleError(err);
      return rejectWithValue(errorMsg);
    }
  }
);

export const fetchDataRevenueChart = createAsyncThunk(
  "dashboards/fetchDataRevenueChart",
  async (values, { rejectWithValue }) => {
    try {
      const res = await getRevenueChartApi(values);
      if (!res) return rejectWithValue("Failed to fetch dashboards");

      return res.data;
    } catch (err) {
      const errorMsg = handleError(err);
      return rejectWithValue(errorMsg);
    }
  }
);

export const fetchDataExpenseChart = createAsyncThunk(
  "dashboards/fetchDataExpenseChart",
  async (values, { rejectWithValue }) => {
    try {
      const res = await getExpenseChartApi(values);
      if (!res) return rejectWithValue("Failed to fetch dashboards");

      return res.data;
    } catch (err) {
      const errorMsg = handleError(err);
      return rejectWithValue(errorMsg);
    }
  }
);

const dashboardSlice = createSlice({
  name: "dashboards",
  initialState: {
    dashboards: null,
    dataRevenue: [],
    dataExpense: [],
    totalDataRevenue: null,
    totalDataExpense: null,
    total: null,
    loading: false,
    error: null,
    filterDashboard: {},
    cache: {},
  },
  reducers: {
    setFilterDashboard(state, action) {
      if (_.isEqual(state.filterDashboard, action.payload)) return;
      state.filterDashboard = { ...state.filterDashboard, ...action.payload };
    },
    clearFilterDashboard(state) {
      state.filterDashboard = {};
    },
    clearError: (state) => {
      state.error = null;
    },
  },
  extraReducers: (builder) => {
    builder
      .addCase(fetchDataLineChart.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchDataLineChart.fulfilled, (state, action) => {
        state.loading = false;
        const result = action.payload;
        if (result) {
          state.dashboards = {
            ...result,
            studentTrend: result.studentTrend || [],
            teacherTrend: result.teacherTrend || [],
          };
          state.total = result.meta;
        }
      })
      .addCase(fetchDataLineChart.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      })

      .addCase(fetchDataRevenueChart.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchDataRevenueChart.fulfilled, (state, action) => {
        state.loading = false;
        const result = action.payload; // Already unwrapped res.data.data
        if (result) {
          state.dataRevenue = result.revenue;
          state.totalDataRevenue = result.meta;
        }
      })
      .addCase(fetchDataRevenueChart.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      })

      .addCase(fetchDataExpenseChart.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchDataExpenseChart.fulfilled, (state, action) => {
        state.loading = false;
        const result = action.payload; // Already unwrapped res.data.data
        if (result) {
          state.dataExpense = result.expense;
          state.totalDataExpense = result.meta;
        }
      })
      .addCase(fetchDataExpenseChart.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });
  },
});

export const { setFilterDashboard, clearFilterDashboard, clearError } =
  dashboardSlice.actions;
export default dashboardSlice.reducer;

