  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 16,
        padding: "24px",
        boxShadow: "0 1px 4px rgba(0,0,0,0.06), 0 2px 8px rgba(0,0,0,0.04)",
        border: "1px solid #F3F4F6",
        height: "100%",
      }}
    >
      <h3 style={{ fontSize: 16, fontWeight: 700, color: "#1F2937", marginBottom: 20 }}>
        Chi phí
      </h3>

      {loading && !dataExpense.length ? (
        <div style={{ height: 220, display: "flex", alignItems: "center", justifyContent: "center", color: "#9CA3AF", fontSize: 14 }}>
          Đang tải...
        </div>
      ) : (
        <div style={{ display: "flex", gap: 20, alignItems: "center" }}>
          {/* Donut Chart */}
          <div style={{ position: "relative", width: 190, height: 190, flexShrink: 0 }}>
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={dataExpense}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={88}
                  paddingAngle={2}
                  dataKey="value"
                  onMouseEnter={(_, index) => setActiveIndex(index)}
                  onMouseLeave={() => setActiveIndex(null)}
                >
                  {dataExpense.map((entry, index) => (
                    <Cell
                      key={`cell-${index}`}
                      fill={entry.color || PALETTE[index % PALETTE.length]}
                      opacity={activeIndex === null || activeIndex === index ? 1 : 0.4}
                      style={{ transition: "opacity 0.2s" }}
                    />
                  ))}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
              </PieChart>
            </ResponsiveContainer>
            {/* Center label */}
            <div
              style={{
                position: "absolute",
                top: "50%",
                left: "50%",
                transform: "translate(-50%, -50%)",
                textAlign: "center",
                pointerEvents: "none",
              }}
            >
              <div style={{ fontSize: 11, color: "#9CA3AF", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>
                Tổng
              </div>
              <div style={{ fontSize: 13, fontWeight: 800, color: "#1F2937", lineHeight: 1.2 }}>
                {totalValue > 0 ? formatTotal(totalValue) : "—"}
              </div>
              <div style={{ fontSize: 10, color: "#9CA3AF" }}>VNĐ</div>
            </div>
          </div>

          {/* Progress bars */}
          <div style={{ flex: 1, minWidth: 0 }}>
            {dataExpense.map((item, idx) => {
              const pct = totalValue > 0 ? Math.round(((item.value || 0) / totalValue) * 100) : 0;
              const color = item.color || PALETTE[idx % PALETTE.length];
              return (
                <div key={item.name || idx} style={{ marginBottom: 10 }}>
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center",
                      marginBottom: 4,
                    }}
                  >
                    <span style={{ fontSize: 12, color: "#374151", fontWeight: 500 }}>{item.name}</span>
                    <span
                      style={{
                        fontSize: 11,
                        fontWeight: 700,
                        color: color,
                      }}
                    >
                      {pct}%
                    </span>
                  </div>
                  <div
                    style={{
                      height: 6,
                      background: "#F3F4F6",
                      borderRadius: 10,
                      overflow: "hidden",
                    }}
                  >
                    <div
                      style={{
                        height: "100%",
                        width: `${pct}%`,
                        background: `linear-gradient(90deg, ${color}cc, ${color})`,
                        borderRadius: 10,
                        transition: "width 0.5s ease",
                      }}
                    />
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

export default CostDonutChart;

